import{_ as e,o as t,c as i,ag as r}from"./chunks/framework.Cqf6AMW8.js";const u=JSON.parse('{"title":"CSS Flex 弹性布局","description":"CSS Flex 弹性布局相关知识，包括容器属性和项目属性。","frontmatter":{"title":"CSS Flex 弹性布局","description":"CSS Flex 弹性布局相关知识，包括容器属性和项目属性。","date":"2026-04-21T00:00:00.000Z","tags":["CSS","Flex","弹性布局"],"sidebar":"auto"},"headers":[],"relativePath":"docs/frontend/css/CSS-基础-5-Flex.md","filePath":"docs/frontend/css/CSS-基础-5-Flex.md","lastUpdated":1776715536000}'),n={name:"docs/frontend/css/CSS-基础-5-Flex.md"};function s(a,l,o,p,c,d){return t(),i("div",null,[...l[0]||(l[0]=[r('<p>#CSS</p><p>======================================================</p><h2 id="_1-flex-弹性布局" tabindex="-1">1. Flex（弹性布局） <a class="header-anchor" href="#_1-flex-弹性布局" aria-label="Permalink to &quot;1. Flex（弹性布局）&quot;">​</a></h2><h3 id="_1-1-容器属性" tabindex="-1">1.1 容器属性 <a class="header-anchor" href="#_1-1-容器属性" aria-label="Permalink to &quot;1.1 容器属性&quot;">​</a></h3><ul><li><p><strong>display: flex</strong>：启用弹性布局</p></li><li><p><strong>flex-direction</strong>：设置主轴方向</p><ul><li>row：水平方向（默认）</li><li>column：垂直方向</li></ul></li><li><p><strong>justify-content</strong>：设置主轴对齐方式</p><ul><li>center：居中对齐</li><li>space-between：两端对齐，间距相等</li><li>space-around：间距环绕</li></ul></li><li><p><strong>align-items</strong>：设置交叉轴对齐方式</p><ul><li>center：居中对齐</li><li>stretch：拉伸填充（默认，子元素没有尺寸才能拉伸）</li></ul></li><li><p><strong>flex-wrap</strong>：设置是否换行</p><ul><li>nowrap：不换行（默认）</li><li>wrap：换行</li></ul></li><li><p><strong>align-content</strong>：设置多行对齐方式</p><ul><li>center：居中对齐</li><li>space-between：两端对齐，间距相等</li><li>space-around：间距环绕</li><li>stretch：拉伸填充（默认）</li></ul></li></ul><p>======================================================</p><h3 id="_1-2-项目属性" tabindex="-1">1.2 项目属性 <a class="header-anchor" href="#_1-2-项目属性" aria-label="Permalink to &quot;1.2 项目属性&quot;">​</a></h3><ul><li><p><strong>flex</strong>：设置项目伸缩比例（可填写px/1、2之类的比例）</p></li><li><p><strong>flex-grow</strong>：设置项目放大比例</p></li><li><p><strong>flex-shrink</strong>：设置项目缩小比例</p></li><li><p><strong>flex-basis</strong>：设置项目初始大小</p></li><li><p><strong>order</strong>：设置项目排列顺序</p></li><li><p><strong>align-self</strong>：设置单个项目对齐方式</p></li></ul><p>======================================================</p>',9)])])}const _=e(n,[["render",s]]);export{u as __pageData,_ as default};
